eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   MARKET_NEWS_ASSET_IMAGES: () => (/* binding */ MARKET_NEWS_ASSET_IMAGES),\n/* harmony export */   MARKET_NEWS_ITEMS: () => (/* binding */ MARKET_NEWS_ITEMS)\n/* harmony export */ });\n/* harmony import */ var _assest_news1_png__WEBPACK_IMPORTED_MODULE_0__ = __webpack_require__(/*! ../assest/news1.png */ \"./src/assest/news1.png\");\n/* harmony import */ var _assest_news2_png__WEBPACK_IMPORTED_MODULE_1__ = __webpack_require__(/*! ../assest/news2.png */ \"./src/assest/news2.png\");\n/* harmony import */ var _assest_news3_png__WEBPACK_IMPORTED_MODULE_2__ = __webpack_require__(/*! ../assest/news3.png */ \"./src/assest/news3.png\");\n/* harmony import */ var _assest_news4_png__WEBPACK_IMPORTED_MODULE_3__ = __webpack_require__(/*! ../assest/news4.png */ \"./src/assest/news4.png\");\n/* harmony import */ var _assest_news5_png__WEBPACK_IMPORTED_MODULE_4__ = __webpack_require__(/*! ../assest/news5.png */ \"./src/assest/news5.png\");\n/* harmony import */ var _assest_news6_png__WEBPACK_IMPORTED_MODULE_5__ = __webpack_require__(/*! ../assest/news6.png */ \"./src/assest/news6.png\");\n/* harmony import */ var _assest_news7_png__WEBPACK_IMPORTED_MODULE_6__ = __webpack_require__(/*! ../assest/news7.png */ \"./src/assest/news7.png\");\n/* harmony import */ var _assest_news8_png__WEBPACK_IMPORTED_MODULE_7__ = __webpack_require__(/*! ../assest/news8.png */ \"./src/assest/news8.png\");\n/* harmony import */ var _assest_news9_png__WEBPACK_IMPORTED_MODULE_8__ = __webpack_require__(/*! ../assest/news9.png */ \"./src/assest/news9.png\");\n/* harmony import */ var _assest_news10_png__WEBPACK_IMPORTED_MODULE_9__ = __webpack_require__(/*! ../assest/news10.png */ \"./src/assest/news10.png\");\n/* harmony import */ var _assest_news11_png__WEBPACK_IMPORTED_MODULE_10__ = __webpack_require__(/*! ../assest/news11.png */ \"./src/assest/news11.png\");\n/* harmony import */ var _assest_news12_png__WEBPACK_IMPORTED_MODULE_11__ = __webpack_require__(/*! ../assest/news12.png */ \"./src/assest/news12.png\");\n/* harmony import */ var _assest_news13_png__WEBPACK_IMPORTED_MODULE_12__ = __webpack_require__(/*! ../assest/news13.png */ \"./src/assest/news13.png\");\n/* harmony import */ var _assest_news14_png__WEBPACK_IMPORTED_MODULE_13__ = __webpack_require__(/*! ../assest/news14.png */ \"./src/assest/news14.png\");\n/* harmony import */ var _assest_news15_png__WEBPACK_IMPORTED_MODULE_14__ = __webpack_require__(/*! ../assest/news15.png */ \"./src/assest/news15.png\");\n/* harmony import */ var _assest_news16_png__WEBPACK_IMPORTED_MODULE_15__ = __webpack_require__(/*! ../assest/news16.png */ \"./src/assest/news16.png\");\n/* harmony import */ var _assest_news16_1_jpg__WEBPACK_IMPORTED_MODULE_16__ = __webpack_require__(/*! ../assest/news16.1.jpg */ \"./src/assest/news16.1.jpg\");\n/* harmony import */ var _assest_news16_2_jpg__WEBPACK_IMPORTED_MODULE_17__ = __webpack_require__(/*! ../assest/news16.2.jpg */ \"./src/assest/news16.2.jpg\");\n/* harmony import */ var _assest_news16_3_jpg__WEBPACK_IMPORTED_MODULE_18__ = __webpack_require__(/*! ../assest/news16.3.jpg */ \"./src/assest/news16.3.jpg\");\n/* harmony import */ var _assest_news16_4_jpg__WEBPACK_IMPORTED_MODULE_19__ = __webpack_require__(/*! ../assest/news16.4.jpg */ \"./src/assest/news16.4.jpg\");\n/* harmony import */ var _assest_news16_5_jpg__WEBPACK_IMPORTED_MODULE_20__ = __webpack_require__(/*! ../assest/news16.5.jpg */ \"./src/assest/news16.5.jpg\");\n/* harmony import */ var _assest_news16_6_jpg__WEBPACK_IMPORTED_MODULE_21__ = __webpack_require__(/*! ../assest/news16.6.jpg */ \"./src/assest/news16.6.jpg\");\n/* harmony import */ var _assest_news16_7_jpg__WEBPACK_IMPORTED_MODULE_22__ = __webpack_require__(/*! ../assest/news16.7.jpg */ \"./src/assest/news16.7.jpg\");\n/* harmony import */ var _assest_news16_8_jpg__WEBPACK_IMPORTED_MODULE_23__ = __webpack_require__(/*! ../assest/news16.8.jpg */ \"./src/assest/news16.8.jpg\");\n/* harmony import */ var _assest_news16_9_jpg__WEBPACK_IMPORTED_MODULE_24__ = __webpack_require__(/*! ../assest/news16.9.jpg */ \"./src/assest/news16.9.jpg\");\n/* harmony import */ var _assest_news16_10_jpg__WEBPACK_IMPORTED_MODULE_25__ = __webpack_require__(/*! ../assest/news16.10.jpg */ \"./src/assest/news16.10.jpg\");\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\nconst MARKET_NEWS_ITEMS = [\n    {\n        id: \"1\",\n        title: \"The Mercor Phenomenon: How Three 22-Year-Olds Built a $10 Billion AI Empire\",\n        image: _assest_news1_png__WEBPACK_IMPORTED_MODULE_0__[\"default\"],\n        updated: \"Dec 31, 2025\",\n        author: \"The Unicorn Time\",\n        description: \"The Day the Resume Died — Mercor crosses 10 million vetted candidates and makes resumes obsolete.\",\n        contentHtml: `\r\n<h2>The Day the Resume Died</h2>\r\n<p>On November 14, 2025, the global recruitment industry faced its &quot;Napster moment.&quot; Mercor, the startup founded by Adarsh Hiremath, Brendan Artley, and Surya Midatala&mdash;all barely 22 years old&mdash;announced a successful Series C funding round that valued the company at a staggering $10.2 Billion. But the valuation wasn't the headline. The real news was that Mercor had officially crossed the threshold of 10 million vetted candidates, making it the largest AI-vetted labor pool in human history.</p>\r\n<p>For decades, the &quot;resume&quot; was the currency of the professional world. In 2025, Mercor finally made it obsolete. By using proprietary AI models to conduct real-time, 30-minute technical and behavioral interviews with millions of workers simultaneously, Mercor has replaced the slow, biased human-led hiring process with a &quot;Liquidity Layer&quot; for human talent.</p>\r\n\r\n<h2>The Origin of the &quot;God-Model&quot; for Labor</h2>\r\n<p>The story of Mercor began in the dorm rooms of 2023, but its 2025 dominance was built on a pivot that few saw coming. Originally a platform to connect Indian developers with US startups, the founders realized that the &quot;bottleneck&quot; wasn't a lack of talent&mdash;it was a lack of trusted data about talent.</p>\r\n<p>In late 2024, they released Mercor-V3, a reasoning-based AI that doesn't just scan keywords but engages in &quot;adversarial interviewing.&quot; If a candidate claims to know Python, the AI enters a live coding environment with them, introduces bugs into their code, and observes their &quot;thinking process&quot; in real-time. By mid-2025, this system was so accurate that companies like Stripe and Airbnb began hiring candidates purely based on their &quot;Mercor Score,&quot; skipping their own internal interview loops entirely.</p>\r\n\r\n<h2>The $10 Billion Valuation: Breakdown of the Deal</h2>\r\n<p>The Series C was led by Benchmark and Sequoia Capital, with significant participation from Peter Thiel&rsquo;s Founders Fund. Industry analysts were initially skeptical of a $10B tag for a three-year-old company, but the numbers provided in the <em>Unicorn Times</em> exclusive leak tell a different story:</p>\r\n\r\n<div class=\"tableWrap\">\r\n  <table class=\"contentTable\">\r\n    <thead>\r\n      <tr>\r\n        <th>Metric</th>\r\n        <th>2024 Performance</th>\r\n        <th>2025 Performance (Proj.)</th>\r\n        <th>Growth (%)</th>\r\n      </tr>\r\n    </thead>\r\n    <tbody>\r\n      <tr>\r\n        <td><strong>Active Candidates</strong></td>\r\n        <td>800,000</td>\r\n        <td>11,200,000</td>\r\n        <td>1,300%</td>\r\n      </tr>\r\n      <tr>\r\n        <td><strong>Placements per Month</strong></td>\r\n        <td>1,200</td>\r\n        <td>25,000</td>\r\n        <td>1,983%</td>\r\n      </tr>\r\n      <tr>\r\n        <td><strong>Annual Recurring Revenue (ARR)</strong></td>\r\n        <td>$140M</td>\r\n        <td>$1.1B</td>\r\n        <td>685%</td>\r\n      </tr>\r\n      <tr>\r\n        <td><strong>AI Interview Accuracy</strong></td>\r\n        <td>88%</td>\r\n        <td>99.4%</td>\r\n        <td>11.4%</td>\r\n      </tr>\r\n    </tbody>\r\n  </table>\r\n</div>\r\n\r\n<h2>Market Disruption: The &quot;Global Meritocracy&quot;</h2>\r\n<p>The impact on the global economy has been profound. Mercor&rsquo;s 2025 data shows that 42% of their high-earning placements ($150k+ USD roles) are now going to individuals in Tier-2 and Tier-3 cities in India, Nigeria, and Vietnam&mdash;people who previously never would have made it past a traditional HR filter.</p>\r\n<p>&quot;We aren't just a job board,&quot; co-founder Surya Midatala stated in a recent keynote. &quot;We are the global index for human capability. If you are the best coder in a small village in Rajasthan, our AI will find you, prove you are the best, and put you in a job at a Silicon Valley giant by next Monday.&quot;</p>\r\n\r\n<h2>The Future: From Recruitment to &quot;Human-AI Hybrid Teams&quot;</h2>\r\n<p>As we look toward 2026, Mercor isn't stopping at hiring. Their newest initiative, Mercor OS, aims to provide companies with a management layer that uses AI to monitor team productivity and suggest &quot;hot-swapping&quot; talent when projects stall. While labor unions have raised concerns about the &quot;commoditization of humans,&quot; the markets remain bullish. For now, the three 22-year-olds are the undisputed kings of the &quot;New Work&quot; era.</p>\r\n`,\n        content: `The Day the Resume Died\r\n\r\nOn November 14, 2025, the global recruitment industry faced its \"Napster moment.\" Mercor, the startup founded by Adarsh Hiremath, Brendan Artley, and Surya Midatala—all barely 22 years old—announced a successful Series C funding round that valued the company at a staggering $10.2 Billion. But the valuation wasn't the headline. The real news was that Mercor had officially crossed the threshold of 10 million vetted candidates, making it the largest AI-vetted labor pool in human history.\r\n\r\nFor decades, the \"resume\" was the currency of the professional world. In 2025, Mercor finally made it obsolete. By using proprietary AI models to conduct real-time, 30-minute technical and behavioral interviews with millions of workers simultaneously, Mercor has replaced the slow, biased human-led hiring process with a \"Liquidity Layer\" for human talent.\r\n\r\nThe Origin of the \"God-Model\" for Labor\r\n\r\nThe story of Mercor began in the dorm rooms of 2023, but its 2025 dominance was built on a pivot that few saw coming. Originally a platform to connect Indian developers with US startups, the founders realized that the \"bottleneck\" wasn't a lack of talent—it was a lack of trusted data about talent.\r\n\r\nIn late 2024, they released Mercor-V3, a reasoning-based AI that doesn't just scan keywords but engages in \"adversarial interviewing.\" If a candidate claims to know Python, the AI enters a live coding environment with them, introduces bugs into their code, and observes their \"thinking process\" in real-time. By mid-2025, this system was so accurate that companies like Stripe and Airbnb began hiring candidates purely based on their \"Mercor Score,\" skipping their own internal interview loops entirely.\r\n\r\nThe $10 Billion Valuation: Breakdown of the Deal\r\n\r\nThe Series C was led by Benchmark and Sequoia Capital, with significant participation from Peter Thiel’s Founders Fund. Industry analysts were initially skeptical of a $10B tag for a three-year-old company, but the numbers provided in the Unicorn Times exclusive leak tell a different story:\r\n\r\nMetric | 2024 Performance | 2025 Performance (Proj.) | Growth (%)\r\nActive Candidates | 800,000 | 11,200,000 | 1,300%\r\nPlacements per Month | 1,200 | 25,000 | 1,983%\r\nAnnual Recurring Revenue (ARR) | $140M | $1.1B | 685%\r\nAI Interview Accuracy | 88% | 99.4% | 11.4%\r\n\r\nMarket Disruption: The \"Global Meritocracy\"\r\n\r\nThe impact on the global economy has been profound. Mercor’s 2025 data shows that 42% of their high-earning placements ($150k+ USD roles) are now going to individuals in Tier-2 and Tier-3 cities in India, Nigeria, and Vietnam—people who previously never would have made it past a traditional HR filter.\r\n\r\n\"We aren't just a job board,\" co-founder Surya Midatala stated in a recent keynote. \"We are the global index for human capability. If you are the best coder in a small village in Rajasthan, our AI will find you, prove you are the best, and put you in a job at a Silicon Valley giant by next Monday.\"\r\n\r\nThe Future: From Recruitment to \"Human-AI Hybrid Teams\"\r\n\r\nAs we look toward 2026, Mercor isn't stopping at hiring. Their newest initiative, Mercor OS, aims to provide companies with a management layer that uses AI to monitor team productivity and suggest \"hot-swapping\" talent when projects stall. While labor unions have raised concerns about the \"commoditization of humans,\" the markets remain bullish. For now, the three 22-year-olds are the undisputed kings of the \"New Labor Market\".`\n    },\n    {\n        id: \"2\",\n        title: \"The India IPO Tsunami: A Record-Breaking Year for the NSE/BSE\",\n        image: _assest_news2_png__WEBPACK_IMPORTED_MODULE_1__[\"default\"],\n        updated: \"Dec 31, 2025\",\n        author: \"The Unicorn Time\",\n        description: \"A historic milestone for Dalal Street as India’s tech sector crosses $1T market cap amid an IPO surge.\",\n        contentHtml: `\r\n<h2>A Historic Milestone for Dalal Street</h2>\r\n<p>If 2021 was the year of the &quot;Unicorn birth,&quot; 2025 has been the year of the &quot;Unicorn Exit.&quot; As of December 31, 2025, India has seen a record 18 tech unicorns go public on the National Stock Exchange (NSE) and Bombay Stock Exchange (BSE). This surge has pushed the total market capitalization of India&rsquo;s tech sector past the $1 Trillion mark for the first time in history.</p>\r\n<p>The primary driver of this trend has been a fundamental shift in the Indian startup ecosystem: the move from &quot;Growth at all Costs&quot; to &quot;Sustainable Profitability.&quot;</p>\r\n\r\n<h2>Zepto&rsquo;s Blockbuster Listing: The 10-Minute IPO</h2>\r\n<p>The crown jewel of the year was Zepto&rsquo;s IPO in August. Despite concerns about the thin margins of the quick-commerce sector, Zepto reported four consecutive profitable quarters leading up to the listing. The IPO was oversubscribed by a staggering 142 times, driven largely by retail investors who have become &quot;Zepto-loyalists.&quot;</p>\r\n<ul>\r\n  <li><strong>Issue Price:</strong> ₹1,200</li>\r\n  <li><strong>Listing Day Pop:</strong> +45% (₹1,740)</li>\r\n  <li><strong>Current Price (Dec 31):</strong> ₹2,450</li>\r\n  <li><strong>Market Cap:</strong> $14.5 Billion</li>\r\n</ul>\r\n<p>Founder Aadit Palicha noted that the success of the IPO was a testament to &quot;Indian logistics excellence.&quot; Zepto now handles more daily deliveries than the traditional postal service in several major metros.</p>\r\n\r\n<h2>The &quot;Great Reset&quot; of 2025: Urban Company and Meesho</h2>\r\n<p>Following Zepto, Urban Company and Meesho also made their highly anticipated debuts. Urban Company&rsquo;s IPO was particularly significant as it marked the first successful public exit for a &quot;Gig-Economy&quot; platform that prioritized worker welfare and high service standards.</p>\r\n<p><strong>Key IPO Stats of 2025:</strong></p>\r\n<ol>\r\n  <li><strong>Meesho:</strong> Raised $850M; focus on Tier-3 e-commerce; stock up 30% since listing.</li>\r\n  <li><strong>Urban Company:</strong> Valued at $4.2B at IPO; unique &quot;Service-as-a-Product&quot; model praised by global analysts.</li>\r\n  <li><strong>MobiKwik:</strong> Finally found its footing in the &quot;Aspirant India&quot; credit market, listing at a $1.8B valuation.</li>\r\n</ol>\r\n\r\n<h2>Why Now? The Role of SEBI and Domestic Capital</h2>\r\n<p>Three factors converged to make 2025 the &quot;Golden Year&quot; for Indian IPOs:</p>\r\n<ul>\r\n  <li><strong>Regulatory Ease:</strong> SEBI introduced the &quot;Confidential Filing&quot; 2.0, allowing startups to test market waters without exposing sensitive data to competitors too early.</li>\r\n  <li><strong>SIP Revolution:</strong> Monthly Systematic Investment Plan (SIP) inflows in India crossed ₹25,000 Crore ($3B) in 2025. This wall of domestic retail money provided a &quot;floor&quot; for IPO valuations, reducing dependence on fickle foreign institutional investors (FIIs).</li>\r\n  <li><strong>Peak XV&rsquo;s Liquidity Push:</strong> The separation of Sequoia India into Peak XV led to a massive drive to return capital to LPs, forcing many late-stage companies to choose the public markets over further private rounds.</li>\r\n</ul>\r\n\r\n<h2>The Road Ahead: The $5 Trillion Economy</h2>\r\n<p>As the bells ring at the BSE to close out 2025, the sentiment is clear: India is no longer just a &quot;back-office&quot; or a &quot;consumer market.&quot; It is a capital-generating powerhouse. With the IPO pipeline for 2026 already looking packed with names like Swiggy (Round 2), Ola Electric (secondary offering), and Pharmeasy, the Indian bull run shows no signs of tiring.</p>\r\n`,\n        content: `A Historic Milestone for Dalal Street\r\n\r\nIf 2021 was the year of the \"Unicorn birth,\" 2025 has been the year of the \"Unicorn Exit.\" As of December 31, 2025, India has seen a record 18 tech unicorns go public on the National Stock Exchange (NSE) and Bombay Stock Exchange (BSE). This surge has pushed the total market capitalization of India’s tech sector past the $1 Trillion mark for the first time in history.\r\n\r\nThe primary driver of this trend has been a fundamental shift in the Indian startup ecosystem: the move from \"Growth at all Costs\" to \"Sustainable Profitability.\"\r\n\r\nZepto’s Blockbuster Listing: The 10-Minute IPO\r\n\r\nThe crown jewel of the year was Zepto’s IPO in August. Despite concerns about the thin margins of the quick-commerce sector, Zepto reported four consecutive profitable quarters leading up to the listing. The IPO was oversubscribed by a staggering 142 times, driven largely by retail investors who have become \"Zepto-loyalists.\"\r\n\r\nIssue Price: ₹1,200\r\nListing Day Pop: +45% (₹1,740)\r\nCurrent Price (Dec 31): ₹2,450\r\nMarket Cap: $14.5 Billion\r\n\r\nThe \"Great Reset\" of 2025: Urban Company and Meesho\r\n\r\nFollowing Zepto, Urban Company and Meesho also made their highly anticipated debuts. Urban Company’s IPO was particularly significant as it marked the first successful public exit for a \"Gig-Economy\" platform that prioritized worker welfare and high service standards.\r\n\r\nKey IPO Stats of 2025:\r\n\r\n1. Meesho: Raised $850M; focus on Tier-3 e-commerce; stock up 30% since listing.\r\n2. Urban Company: Valued at $4.2B at IPO; unique \"Service-as-a-Product\" model praised by global analysts.\r\n3. MobiKwik: Finally found its footing in the \"Aspirant India\" credit market, listing at a $1.8B valuation.\r\n\r\nWhy Now? The Role of SEBI and Domestic Capital\r\n\r\nThree factors converged to make 2025 the \"Golden Year\" for Indian IPOs:\r\n\r\nRegulatory Ease: SEBI introduced the \"Confidential Filing\" 2.0.\r\nSIP Revolution: Monthly SIP inflows crossed ₹25,000 Crore ($3B) in 2025.\r\nPeak XV’s Liquidity Push: Massive drive to return capital.\r\n\r\nThe Road Ahead: The $5 Trillion Economy\r\n\r\nAs the bells ring at the BSE to close out 2025, the sentiment is clear: India is no longer just a \"back-office\" or a \"consumer market.\" It is a capital-generating powerhouse.`\n    },\n    {\n        id: \"3\",\n        title: \"The DeepSeek Shockwave: The Day the AI Compute Bubble Popped\",\n        image: _assest_news3_png__WEBPACK_IMPORTED_MODULE_2__[\"default\"],\n        updated: \"Dec 31, 2025\",\n        author: \"The Unicorn Time\",\n        description: \"DeepSeek-R1 proves top-tier reasoning needs far less compute—triggering an ‘efficiency crash’ across markets.\",\n        contentHtml: `\r\n<h2>The &quot;Nvidia Correction&quot; Heard 'Round the World</h2>\r\n<p>For the first half of 2025, Nvidia was the most valuable company on Earth, flirting with a $4.5 Trillion market cap. But on October 12, 2025, the market experienced what is now known as the &quot;Efficiency Crash.&quot; In a single week, Nvidia&rsquo;s stock plummeted by 22%, wiping out nearly $1 Trillion in value.</p>\r\n<p>The catalyst? The global release of DeepSeek-R1, a &quot;Reasoning Model&quot; out of China that proved AI intelligence could be achieved with one-tenth of the compute power previously thought necessary.</p>\r\n\r\n<h2>Brute Force vs. Elegant Reasoning</h2>\r\n<p>Since the launch of ChatGPT in 2022, the AI industry operated on a &quot;Scaling Law&quot;: more GPUs + more data = more intelligence. This led to a desperate &quot;arms race&quot; for Nvidia&rsquo;s H100 and B200 chips. Microsoft, Google, and Meta spent hundreds of billions on massive data centers.</p>\r\n<p>DeepSeek-R1 changed the math. By using a novel architecture known as &quot;Sparse Reasoning Paths,&quot; the model achieved performance scores equivalent to GPT-5 but was trained on a cluster of just 2,000 mid-grade chips.</p>\r\n<p>&quot;The era of 'Brute Force AI' is over,&quot; said Dr. Fei-Fei Li in a widely cited symposium. &quot;DeepSeek proved that we don't need a sun's worth of energy to power a smart chatbot. We just needed better algorithms.&quot;</p>\r\n\r\n<h2>The Economic Fallout: Winners and Losers</h2>\r\n<p>The &quot;DeepSeek Shock&quot; sent ripples through the entire S&amp;P 500. While Nvidia took a hit, software companies and &quot;Edge AI&quot; startups soared.</p>\r\n<p><strong>The 2025 AI Market Shift:</strong></p>\r\n<ul>\r\n  <li><strong>Losing Big:</strong> Hardware providers and energy companies focused on &quot;Mega-Data-Centers.&quot; (Nvidia, Super Micro, Constellation Energy).</li>\r\n  <li><strong>Winning Big:</strong> Application-layer startups. Suddenly, the &quot;Cost per Query&quot; for AI fell from $0.01 to $0.0001. This made AI-integrated consumer apps (like real-time voice translators and personalized AI tutors) finally profitable.</li>\r\n</ul>\r\n\r\n<h2>Geopolitics: The US-China AI Cold War</h2>\r\n<p>The success of DeepSeek has raised intense questions in Washington. Despite stringent US chip sanctions, the Chinese AI ecosystem managed to innovate its way around the hardware deficit. In response, the US Department of Commerce has proposed the &quot;Compute Sovereignty Act&quot; of late 2025, which subsidizes &quot;Algorithm-First&quot; research rather than just hardware manufacturing.</p>\r\n\r\n<h2>Conclusion: A New Paradigm for 2026</h2>\r\n<p>As we enter 2026, the AI industry is no longer obsessed with &quot;Who has the most chips?&quot; The new question is &quot;Who has the most efficient code?&quot; This shift is democratizing AI; smaller startups can now compete with tech giants because they no longer need a $10 Billion compute budget to build a world-class model.</p>\r\n<p>The &quot;Gilded Age&quot; of GPUs may be over, but the &quot;Age of Intelligent Efficiency&quot; has just begun.</p>\r\n`,\n        content: `The \"Nvidia Correction\" Heard 'Round the World\r\n\r\nFor the first half of 2025, Nvidia was the most valuable company on Earth, flirting with a $4.5 Trillion market cap. But on October 12, 2025, the market experienced what is now known as the \"Efficiency Crash.\" In a single week, Nvidia’s stock plummeted by 22%, wiping out nearly $1 Trillion in value.\r\n\r\nThe catalyst? The global release of DeepSeek-R1, a \"Reasoning Model\" out of China that proved AI intelligence could be achieved with one-tenth of the compute power previously thought necessary.\r\n\r\nBrute Force vs. Elegant Reasoning\r\n\r\nDeepSeek-R1 changed the math. By using a novel architecture known as \"Sparse Reasoning Paths,\" the model achieved performance scores equivalent to GPT-5 but was trained on a cluster of just 2,000 mid-grade chips.\r\n\r\nConclusion: A New Paradigm for 2026\r\n\r\nAs we enter 2026, the AI industry is no longer obsessed with \"Who has the most chips?\" The new question is \"Who has the most efficient code?\"`\n    },\n    {\n        id: \"4\",\n        title: \"The Trillion-Dollar Frontier: How 2025 Became the Year Asteroid Mining Moved from Sci-Fi to Series C\",\n        image: _assest_news4_png__WEBPACK_IMPORTED_MODULE_3__[\"default\"],\n        updated: \"Dec 31, 2025\",\n        author: \"The Unicorn Time\",\n        description: \"AstroForge’s Odin flyby confirms platinum-rich asteroid signatures and ignites a new space resource rush.\",\n        contentHtml: `\r\n<h2>The Flyby That Changed Everything</h2>\r\n<p>As the final seconds of 2025 tick away, the headquarters of AstroForge in Huntington Beach, California, feels less like a startup office and more like a historical landmark. On December 15, 2025, the company&rsquo;s Odin spacecraft successfully executed its high-velocity flyby of the near-Earth object 2022 OB5. The data packets that trickled back through the Deep Space Network didn't just contain blurry photos; they contained spectral signatures that confirmed every investor&rsquo;s wildest dream: a metallic composition rich in Platinum Group Metals (PGMs).</p>\r\n<p>For decades, asteroid mining was a punchline&mdash;a concept relegated to the same &quot;perpetually ten years away&quot; bucket as nuclear fusion and flying cars. But in 2025, the punchline became a gold mine. The Odin mission&rsquo;s success has triggered a &quot;Lunar Gold Rush&quot; atmosphere, leading to a record-breaking $600 million Series C round for AstroForge, led by a syndicate of sovereign wealth funds and traditional mining giants like Rio Tinto.</p>\r\n\r\n<h2>The Technical Triumph of Odin</h2>\r\n<p>The Odin mission was built on a philosophy of &quot;Iterative Risk.&quot; Unlike traditional NASA missions that spend billions to ensure 99.9% success, AstroForge built Odin for just $3.5 million in under ten months. This &quot;move fast and break things&quot; approach for deep space was a gamble. Earlier missions, like the Brokkr-1, suffered from communication failures and power quirks. But Odin was the &quot;Redemption Probe.&quot;</p>\r\n<p>Equipped with a multispectral camera and a high-resolution surface analyzer, Odin traveled over 300,000 km to intercept 2022 OB5. The spectral data returned on December 20th showed a concentration of platinum that is 20 to 50 times higher than the richest terrestrial mines in South Africa.</p>\r\n\r\n<h2>The Economic Catalyst: The Great Platinum Deficit</h2>\r\n<p>Why is the world suddenly obsessed with space rocks? The answer lies in a global resource crisis. According to the World Platinum Investment Council (WPIC), 2025 marked the third consecutive year of massive platinum deficits, reaching nearly 1 million ounces (966koz).</p>\r\n<p>Terrestrial mining is hitting a wall. Ore grades are falling, environmental regulations are tightening, and the energy cost of extracting a single ounce of platinum now involves moving tons of earth. Meanwhile, the demand for PGMs is skyrocketing&mdash;not just for jewelry, but as essential catalysts for the Green Hydrogen economy and the high-performance electronics required for AI data centers.</p>\r\n\r\n<div class=\"tableWrap\">\r\n  <table class=\"contentTable\">\r\n    <thead>\r\n      <tr>\r\n        <th>Metric</th>\r\n        <th>Terrestrial Mining (Avg)</th>\r\n        <th>Asteroid 2022 OB5 (Estimated)</th>\r\n      </tr>\r\n    </thead>\r\n    <tbody>\r\n      <tr>\r\n        <td><strong>Platinum Concentration</strong></td>\r\n        <td>3-5 grams per ton</td>\r\n        <td>150-300 grams per ton</td>\r\n      </tr>\r\n      <tr>\r\n        <td><strong>Environmental Cost</strong></td>\r\n        <td>High (Land displacement/water)</td>\r\n        <td>Minimal (Space-based)</td>\r\n      </tr>\r\n      <tr>\r\n        <td><strong>Scalability</strong></td>\r\n        <td>Limited by Earth's crust</td>\r\n        <td>Virtually limitless</td>\r\n      </tr>\r\n      <tr>\r\n        <td><strong>Unit Cost of Extraction</strong></td>\r\n        <td>Rising</td>\r\n        <td>Falling (as launch costs drop)</td>\r\n      </tr>\r\n    </tbody>\r\n  </table>\r\n</div>\r\n\r\n<h2>Legal Skies: The Artemis Accords and Property Rights</h2>\r\n<p>The success of Odin has forced a diplomatic scramble. In late 2025, the UN Office for Outer Space Affairs (UNOOSA) held an emergency summit to discuss the &quot;Commercial Exploitation of Celestial Bodies.&quot; While the Outer Space Treaty of 1967 forbids national sovereignty over space, the Artemis Accords&mdash;now signed by over 50 nations&mdash;provide a framework for private entities to extract and own resources.</p>\r\n<p>&quot;Possession is nine-tenths of the law in orbit,&quot; says space lawyer Dr. Elena Vance. &quot;AstroForge isn't claiming the asteroid; they are claiming the material they remove. It&rsquo;s the same legal logic as fishing in international waters.&quot;</p>\r\n\r\n<h2>The Roadmap to 2030: From Probes to Refineries</h2>\r\n<p>With the Odin flyby complete, the industry is looking toward DeepSpace-2, scheduled for launch in late 2026. This 200kg spacecraft won't just fly by; it aims to be the first private craft to land on a body outside of a planetary gravity well.</p>\r\n<p>The long-term vision is a &quot;Space-Based Refinery.&quot; AstroForge intends to process the material in situ, using the vacuum of space to refine iron and nickel, bringing back only the high-value PGMs. This eliminates the need to transport useless rock back to Earth, drastically improving the ROI.</p>\r\n`,\n        content: `The Flyby That Changed Everything\r\n\r\nAs the final seconds of 2025 tick away, the headquarters of AstroForge in Huntington Beach, California, feels less like a startup office and more like a historical landmark. On December 15, 2025, the company’s Odin spacecraft successfully executed its high-velocity flyby of the near-Earth object 2022 OB5. The data packets that trickled back through the Deep Space Network didn't just contain blurry photos; they contained spectral signatures that confirmed every investor’s wildest dream: a metallic composition rich in Platinum Group Metals (PGMs).`\n    },\n    {\n        id: \"5\",\n        title: \"The End of the 'Lab Rat' Era: Insilico Medicine and the $100 Billion AI-Drug Revolution\",\n        image: _assest_news5_png__WEBPACK_IMPORTED_MODULE_4__[\"default\"],\n        updated: \"Dec 31, 2025\",\n        author: \"The Unicorn Time\",\n        description: \"Insilico’s AI pipeline accelerates drug discovery and signals a new era of predictive biology.\",\n        contentHtml: `\r\n<h2>The Breaking of &quot;Eroom&rsquo;s Law&quot;</h2>\r\n<p>For sixty years, the pharmaceutical industry was haunted by Eroom&rsquo;s Law (Moore&rsquo;s Law spelled backward). It stated that the cost of developing a new drug doubles every nine years, despite technological advances. By 2024, the average cost to bring a drug to market had ballooned to $2.5 Billion, with a 90% failure rate in clinical trials.</p>\r\n<p>On December 31, 2025, Insilico Medicine effectively declared Eroom's Law dead. Their lead drug candidate, ISM001-055 (Rentosertib), has just completed its 2025 clinical evaluation cycle with results that have sent shockwaves through the medical community. It is the first drug in history to go from AI-target discovery to Phase 2a success in less than 30 months, at a fraction of the traditional cost.</p>\r\n\r\n<h2>Targeting TNIK: The AI&rsquo;s Secret Weapon</h2>\r\n<p>ISM001-055 targets a protein called TNIK (Traf2- and Nck-interacting kinase), which the AI identified as a &quot;master switch&quot; for Idiopathic Pulmonary Fibrosis (IPF)&mdash;a fatal lung-scarring disease. Humans had overlooked TNIK for decades because its biological pathways were too complex for manual mapping.</p>\r\n<p>Insilico&rsquo;s AI platform, PandaOmics, didn't just find the target; its sister platform, Chemistry42, designed the &quot;perfect key&quot; to fit it.</p>\r\n\r\n<h2>The 2025 Clinical Data Reveal</h2>\r\n<p>The 2025 year-end report from Insilico&rsquo;s multi-center trials (spanning the US, China, and the UAE) showed that patients receiving the 60mg dose of Rentosertib experienced a 98.4 mL mean improvement in Forced Vital Capacity (FVC).</p>\r\n<p>To put that in perspective:</p>\r\n<ul>\r\n  <li><strong>Current Standard of Care:</strong> Only slows the decline of lung function.</li>\r\n  <li><strong>AI-Generated ISM001-055:</strong> Actually showed signs of reversing the fibrosis.</li>\r\n</ul>\r\n\r\n<h2>The &quot;Drug Factory&quot; of the Future</h2>\r\n<p>The success of Rentosertib has validated the &quot;End-to-End AI&quot; model. Insilico&rsquo;s pipeline now boasts over 30 AI-designed assets, including potential cures for several types of cancer and age-related diseases. This has triggered a massive M&amp;A (Mergers and Acquisitions) wave. In the final quarter of 2025, Big Pharma giants like Pfizer and Novartis reportedly allocated over 40% of their R&amp;D budgets to AI partnerships.</p>\r\n\r\n<h2>The Ethics of &quot;Black Box&quot; Biology</h2>\r\n<p>However, the rise of AI medicine is not without controversy. Regulators are grappling with &quot;explainability.&quot; If an AI designs a molecule that works, but human scientists can&rsquo;t fully explain the secondary interactions, is it safe?</p>\r\n<p>&quot;We are moving from an era of 'trial and error' to an era of 'predictive biology,'&quot; says Dr. Alex Zhavoronkov, CEO of Insilico. &quot;The AI doesn't have a bias; it only looks at the data. The results speak for themselves.&quot;</p>\r\n\r\n<h2>Market Outlook: The $16 Billion AI-Drug Market</h2>\r\n<p>The global market for AI in drug discovery is projected to hit $16.5 billion by 2035, but analysts at Unicorn Times believe this is an underestimate. If the success rate of Phase 1 trials increases from 10% to just 30% thanks to AI vetting, the global pharmaceutical sector will see an additional $1 Trillion in value created by the end of the decade.</p>\r\n`,\n        content: `The Breaking of \"Eroom’s Law\"\r\n\r\nInsilico Medicine demonstrated unprecedented speed from AI-target discovery to Phase 2a success, challenging decades of pharma development assumptions.`\n    },\n    {\n        id: \"6\",\n        title: \"Taming the Sun: Inside the 2025 Breakthroughs at Commonwealth Fusion Systems\",\n        image: _assest_news6_png__WEBPACK_IMPORTED_MODULE_5__[\"default\"],\n        updated: \"Dec 31, 2025\",\n        author: \"The Unicorn Time\",\n        description: \"CFS scales SPARC engineering and partners with DeepMind to solve plasma control—accelerating fusion timelines.\",\n        contentHtml: `\r\n<h2>The Assembly of the Century</h2>\r\n<p>In the quiet town of Devens, Massachusetts, a revolution is being bolted together piece by piece. As of December 2025, Commonwealth Fusion Systems (CFS) has officially transitioned from a theoretical research project to a massive-scale industrial operation. The goal is simple but world-changing: to create the first &quot;commercially relevant&quot; net-energy fusion machine.</p>\r\n<p>On October 28, 2025, the company celebrated a massive milestone: the arrival of the 48-ton central vacuum vessel, the &quot;heart&quot; where the fusion reaction will occur. This followed the installation of the cryostat base earlier in the year&mdash;a 75-ton steel foundation designed to support the 1,000-ton weight of the SPARC reactor.</p>\r\n\r\n<h2>The AI Advantage: The Google DeepMind Alliance</h2>\r\n<p>One of the most significant developments of 2025 wasn't made of steel, but of code. In October, CFS announced a historic AI Alliance with Google DeepMind. Fusion has always faced a &quot;control problem&quot;: how do you hold a 100-million-degree plasma stable using magnetic fields without it touching the walls of the reactor?</p>\r\n<p>By utilizing DeepMind&rsquo;s reinforcement learning models, CFS has successfully simulated &quot;magnetic steering&quot; that reacts in microseconds&mdash;faster than any human or traditional algorithm could manage. This partnership has effectively shaved two years off the timeline for &quot;First Plasma,&quot; now confidently scheduled for early 2027.</p>\r\n\r\n<h2>The Physics of $Q &gt; 1$</h2>\r\n<p>The holy grail of fusion is the $Q$ factor&mdash;the ratio of energy produced to energy consumed.</p>\r\n<div class=\"equation\">Q = Energy Out / Energy In</div>\r\n<p>For decades, the world has been stuck at $Q &lt; 1$. SPARC is designed to achieve $Q \\approx 11$, meaning for every 1 unit of energy put in to heat the plasma, 11 units of fusion energy are released. In 2025, CFS completed the manufacturing of its High-Temperature Superconducting (HTS) magnets, which are 100 times more powerful than the magnets used in previous generation reactors, allowing SPARC to be significantly smaller and cheaper.</p>\r\n\r\n<h2>The Market Impact: A Post-Scarcity World?</h2>\r\n<p>Wall Street is already reacting to the &quot;Fusion Signal.&quot; While commercial power on the grid isn't expected until the early 2030s via the ARC power plant in Virginia, the 2025 progress has triggered a massive divestment from long-term natural gas infrastructure.</p>\r\n<p>&quot;If CFS hits its 2027 target,&quot; says energy analyst Marcus Thorne, &quot;the cost of electricity could drop to near-zero by 2040. We are looking at the end of the carbon age and the beginning of the 'Star Power' age.&quot;</p>\r\n`,\n        content: `The Assembly of the Century\r\n\r\nCommonwealth Fusion Systems transitioned into industrial-scale assembly, with SPARC targeting commercial relevance and $Q > 1 breakthroughs.`\n    },\n    {\n        id: \"7\",\n        title: \"The Great Reset: How the 2025 'Down-Round' Purge Saved the Startup Ecosystem\",\n        image: _assest_news7_png__WEBPACK_IMPORTED_MODULE_6__[\"default\"],\n        updated: \"Dec 31, 2025\",\n        author: \"The Unicorn Time\",\n        description: \"2025 recalibrates startup valuations and rewards profitability over growth-at-all-costs.\",\n        contentHtml: `\r\n<h2>The End of the &quot;Unicorn&quot; Illusion</h2>\r\n<p>For the startup world, 2025 will be remembered as the Year of the Great Recalibration. After the &quot;funding winter&quot; of 2023 and 2024, many experts expected a total collapse. Instead, 2025 saw a fascinating paradox: fewer startup shutdowns, but more high-profile stumbles.</p>\r\n<p>According to year-end data from Tracxn, India saw only 730 startup closures in 2025, compared to nearly 4,000 in 2024. However, the companies that did fail were the &quot;fallen gods&quot; of the previous era. The exit of Dunzo (with its founder moving to Flipkart's 'Minutes' arm) and the struggles of the Good Glamm Group signaled the final death of the &quot;Growth-at-all-Costs&quot; model.</p>\r\n\r\n<h2>Survival of the Profitable</h2>\r\n<p>The &quot;Unicorn Times&quot; 2025 Sentiment Index shows that VCs have completely rewired their investment criteria. In 2021, the most important metric was GMV (Gross Merchandise Value). In 2025, it is EBITDA (Earnings Before Interest, Taxes, Depreciation, and Amortization).</p>\r\n<p><strong>The 2025 VC Hierarchy:</strong></p>\r\n<ol>\r\n  <li><strong>The &quot;Roach&quot; Startups:</strong> Low burn, high resilience, and cash-flow positive. These companies saw their valuations double in 2025.</li>\r\n  <li><strong>The &quot;Phoenix&quot; Startups:</strong> Former high-burners that underwent painful 50% &quot;Down-Rounds&quot; in late 2024 but emerged in 2025 with lean, profitable operations.</li>\r\n  <li><strong>The AI-First Cohort:</strong> While the rest of the market cooled, AI and HealthTech seed rounds saw a 18% increase in median valuation, reaching $16M.</li>\r\n</ol>\r\n\r\n<h2>The &quot;Down-Round&quot; Redemption</h2>\r\n<p>The term &quot;Down-Round&quot; (raising money at a lower valuation than the previous round) used to be a death sentence. In 2025, it became a badge of survival. By slashing over-inflated 2021 valuations, companies like Meesho and Urban Company were able to clean up their cap tables and prepare for their successful 2025 IPOs (as discussed in News 2).</p>\r\n\r\n<h2>The Founder Shift: From Celebrity to Operator</h2>\r\n<p>The most profound change in 2025 has been cultural. The &quot;Celebrity Founder&quot; era is over. Founders who spent 2024 on &quot;apology tours&quot; for financial mismanagement have been replaced by a new class of &quot;Technical Operators.&quot; These leaders are more likely to be found in a GitHub repository than on a magazine cover.</p>\r\n<p>As we head into 2026, the ecosystem is &quot;sober but strong.&quot; The excess has been burned away, leaving behind a foundation of companies that actually make money.</p>\r\n`,\n        content: `The End of the \"Unicorn\" Illusion\r\n\r\nWith fewer shutdowns but bigger stumbles, 2025 rewired VC criteria toward EBITDA and resilience.`\n    },\n    {\n        id: \"8\",\n        title: \"Silicon Sovereignty: The 2025 Reshaping of the Global Semiconductor Map\",\n        image: _assest_news8_png__WEBPACK_IMPORTED_MODULE_7__[\"default\"],\n        updated: \"Dec 31, 2025\",\n        author: \"The Unicorn Time\",\n        description: \"TSMC Arizona reaches HVM; Intel ships Panther Lake; geopolitics hardens into a new ‘Chip Curtain’.\",\n        contentHtml: `\r\n<h2>The &quot;American Silicon Renaissance&quot;</h2>\r\n<p>On December 29, 2025, the global balance of technological power shifted. For decades, the world's most advanced chips were made almost exclusively in Taiwan and South Korea. But as we close out 2025, TSMC&rsquo;s Arizona Fab 1 has officially reached &quot;High-Volume Manufacturing&quot; (HVM) status on US soil.</p>\r\n<p>This achievement, fueled by the CHIPS and Science Act, represents the largest industrial pivot in American history. TSMC didn't just open a factory; they announced in March 2025 that they were increasing their US investment to a staggering $165 Billion, adding three more fabs and an R&amp;D center to their Phoenix campus.</p>\r\n\r\n<h2>Intel&rsquo;s &quot;Comeback Kid&quot; Moment</h2>\r\n<p>While TSMC dominated the headlines, Intel pulled off the most unlikely turnaround of the year. After a disastrous 2024 where its stock cratered, Intel CEO Pat Gelsinger's &quot;Five Nodes in Four Years&quot; strategy finally paid off.</p>\r\n<p>In late 2025, Intel began shipping Panther Lake, the first high-volume chip built on the Intel 18A (1.8nm) process. By being the first to successfully implement &quot;PowerVia&quot; (backside power delivery) and &quot;RibbonFET&quot; (Gate-All-Around) technology, Intel has&mdash;for the first time in a decade&mdash;technically caught up to, and in some areas surpassed, TSMC&rsquo;s manufacturing lead.</p>\r\n\r\n<h2>The Ohio Delay and the &quot;GPU Gap&quot;</h2>\r\n<p>However, the road wasn't entirely smooth. Intel was forced to push back the completion of its $28 Billion Ohio campus to 2030, citing a shift in market demand from CPUs to AI-specific GPUs.</p>\r\n<p>The semiconductor market in late 2025 is bifurcated:</p>\r\n<ul>\r\n  <li><strong>The AI Boom:</strong> High-Bandwidth Memory (HBM) and GPUs (Nvidia/AMD) are still in a &quot;supply-constrained&quot; state.</li>\r\n  <li><strong>The Mature Node Glut:</strong> Chips for cars and basic appliances are seeing an oversupply as China floods the market with 28nm and 45nm legacy chips.</li>\r\n</ul>\r\n\r\n<h2>Geopolitics: The &quot;Chip Curtain&quot;</h2>\r\n<p>The 2025 landscape is defined by the &quot;Chip Curtain.&quot; New regulations passed in mid-2025 have effectively banned the export of any equipment capable of manufacturing chips below 7nm to &quot;non-allied&quot; nations. This has forced China to accelerate its domestic innovation (as seen with DeepSeek in News 3), creating two entirely separate tech ecosystems: a Western-aligned &quot;Efficiency&quot; chain and a Chinese &quot;Algorithmic-Workaround&quot; chain.</p>\r\n\r\n<h2>Looking Toward 2026: The 2nm Race</h2>\r\n<p>As the bells ring for the New Year, the industry is already looking at the 2026 &quot;Next Step.&quot; Both Intel and TSMC are racing to bring 2nm (2-nanometer) production to scale. The winner of this race will control the brains of every smartphone, EV, and AI agent on the planet.</p>\r\n`,\n        content: `The \"American Silicon Renaissance\"\r\n\r\nTSMC’s US expansion and Intel’s process comeback reshape global chip manufacturing and strategic supply chains.`\n    },\n    {\n        id: \"9\",\n        title: \"The Great EV Flip: How BYD Claimed the Crown as Tesla Pivoted to the ‘Robotaxi Era’\",\n        image: _assest_news9_png__WEBPACK_IMPORTED_MODULE_8__[\"default\"],\n        updated: \"Dec 31, 2025\",\n        author: \"The Unicorn Time\",\n        description: \"BYD overtakes Tesla in BEV volume while Tesla goes all-in on autonomy and robotaxi economics.\",\n        contentHtml: `\r\n<h2>The Statistical Surrender</h2>\r\n<p>On December 30, 2025, the final tallies for global automotive sales confirmed what analysts had whispered since mid-year: BYD is the new king of the road. By the end of November, Shenzhen-headquartered BYD had recorded 2.07 million pure electric vehicle (BEV) sales, comfortably outpacing Tesla&rsquo;s year-end projection of 1.65 million units. For Tesla, 2025 represented a painful 7.7% decrease in annual sales&mdash;the first major contraction in the company's history. The &quot;Tesla Era&quot; of volume dominance has officially ended, but in its place, a more complex, AI-driven strategy is emerging.</p>\r\n\r\n<h2>The &quot;September Cliff&quot; and the Policy Shift</h2>\r\n<p>The primary catalyst for the US market shift was the expiration of the $7,500 federal EV tax credit at the end of September 2025. This policy change, backed by the new administration, triggered a massive &quot;buy-now&quot; surge in the third quarter (nearly 500,000 units sold in 3 months), followed by a devastating demand cliff in Q4.</p>\r\n<p>While Tesla struggled with the loss of subsidies, BYD thrived by leaning into its vertical integration. BYD manufactures its own batteries, semiconductors, and motors, allowing it to maintain margins even while slashing prices to penetrate the European and Southeast Asian markets. In 2025, the BYD Seagull became the world&rsquo;s most popular EV, with a price point under $12,000 that Western manufacturers simply could not match.</p>\r\n\r\n<h2>Tesla&rsquo;s Pivot: The &quot;All-In&quot; on Autonomy</h2>\r\n<p>Elon Musk, however, appears unfazed by the sales crown loss. In a series of 2025 town halls, Musk reiterated that Tesla is no longer a &quot;car company&quot; but an &quot;AI and Robotics powerhouse.&quot;</p>\r\n<p>The focus has shifted entirely to FSD (Full Self-Driving) v13 and the Cybercab. With production of the steering-wheel-less robotaxi slated for April 2026, Tesla spent much of 2025 repurposing its Gigafactories to act as compute centers as much as assembly lines. The goal is to move from selling &quot;hardware with a margin&quot; to &quot;miles as a service,&quot; with 2025 serving as the bridge year where the company sacrificed volume for software development.</p>\r\n\r\n<h2>The Rise of the &quot;Safety Net&quot;: Hybrid Dominance</h2>\r\n<p>Perhaps the most surprising trend of 2025 was the resurgence of the EREV (Extended Range Electric Vehicle). Consumers in India, Brazil, and even North America began favoring vehicles with small gasoline engines that only act as generators for the electric motor.</p>\r\n<ul>\r\n  <li><strong>Toyota's Vindication:</strong> After years of criticism for being &quot;slow&quot; to go all-electric, Toyota&rsquo;s hybrid-heavy 2025 lineup saw record profits.</li>\r\n  <li><strong>The Infrastructure Reality:</strong> The plateau in BEV growth highlighted the lagging pace of charging infrastructure, making &quot;hybrid&quot; the pragmatic word of the year for the global middle class.</li>\r\n</ul>\r\n`,\n        content: `The Statistical Surrender\r\n\r\nBYD’s scale and vertical integration delivered dominance in 2025, while Tesla prioritized autonomy and platform transition.`\n    },\n    {\n        id: \"10\",\n        title: \"The Sovereign Agent: How 2025 Killed the Chatbot and Birthed the ‘Operator'\",\n        image: _assest_news10_png__WEBPACK_IMPORTED_MODULE_9__[\"default\"],\n        updated: \"Dec 31, 2025\",\n        author: \"The Unicorn Time\",\n        description: \"AI shifts from chat to action—agents become outcome-driven operators across consumer and enterprise workflows.\",\n        contentHtml: `\r\n<h2>From &quot;Ask Me Anything&quot; to &quot;Do It For Me&quot;</h2>\r\n<p>In 2023, we talked to AI. In 2024, AI wrote for us. In 2025, AI acted for us. This year marked the transition from Large Language Models (LLMs) to Large Action Models (LAMs). The &quot;Chatbot Era&quot;&mdash;characterized by the ChatGPT interface&mdash;is being replaced by the &quot;Operator Era.&quot; Leading this charge were platforms like Salesforce&rsquo;s Agentforce and OpenAI&rsquo;s 'Operator' project, which achieved general availability in mid-2025.</p>\r\n\r\n<h2>The Agentic Economy</h2>\r\n<p>An AI Agent in 2025 is not just a search tool; it is a software entity with Sovereignty.</p>\r\n<ul>\r\n  <li><strong>Autonomous Tasks:</strong> In 2025, the average &quot;Prosumer&quot; now uses an agent to handle complex workflows&mdash;e.g., &quot;Find a flight to London under $800, book it, update my calendar, and draft an out-of-office reply for my clients.&quot;</li>\r\n  <li><strong>The Death of the 'Seat-Based' Model:</strong> The SaaS industry is in a panic. Why pay for 100 seats of a CRM when one AI Agent can perform the data entry and lead generation of 50 humans? Pricing models in late 2025 are shifting toward &quot;Outcome-Based Billing&quot;&mdash;you pay when the AI completes a sale, not when a human logs in.</li>\r\n</ul>\r\n\r\n<h2>The Rise of Localized/Sovereign AI</h2>\r\n<p>Privacy concerns reached a boiling point in 2025, leading to the rise of the &quot;Sovereign Agent.&quot; Instead of sending every request to a cloud-based server at OpenAI or Google, millions of users are now running &quot;Small Language Models&quot; (SLMs) locally on their AI PCs (equipped with the latest chips from Intel and Nvidia, as discussed in News 8). These agents live on the device, ensuring that personal financial data and private conversations never leave the user's hardware.</p>\r\n\r\n<h2>Institutional Multi-Agent Systems (MAS)</h2>\r\n<p>In the corporate world, 2025 saw the birth of Multi-Agent Systems. In major banks like JP Morgan, &quot;swarms&quot; of AI agents now work together. One agent monitors for fraud, another verifies the identity, and a third executes the transaction&mdash;all in milliseconds. This coordination has reduced operational costs in the financial sector by an estimated 22% in 2025 alone.</p>\r\n`,\n        content: `From \"Ask Me Anything\" to \"Do It For Me\"\r\n\r\n2025 marked the transition from LLMs to action-oriented agents, changing SaaS pricing and productivity models.`\n    },\n    {\n        id: \"11\",\n        title: \"The 100-Ton Door: How SpaceX Starship Democratized Orbit in 2025\",\n        image: _assest_news11_png__WEBPACK_IMPORTED_MODULE_10__[\"default\"],\n        updated: \"Dec 31, 2025\",\n        author: \"The Unicorn Time\",\n        description: \"Starship cadence unlocks cheap payload-to-orbit, enabling new industrialization and direct-to-cell connectivity.\",\n        contentHtml: `\r\n<h2>The Year of the &quot;Starship Cadence&quot;</h2>\r\n<p>2025 was the year the &quot;impossible&quot; became a weekly routine. SpaceX ended the year with a record-breaking 330 orbital launches globally (including Falcon 9), but the true story was the Starship Block 2.</p>\r\n<p>Following the historic success of catching the Super Heavy booster in late 2024, SpaceX achieved &quot;Full Rapid Reusability&quot; of the upper stage in June 2025. By October, Starship had successfully completed 11 flights, with the last six being flawless successes. The &quot;100-Ton Door&quot; to space is now officially open, with the capability to lift massive payloads to orbit for less than $200 per kilogram&mdash;a 90% reduction from the Falcon 9 era.</p>\r\n\r\n<h2>The Starlink v3 and the &quot;Direct-to-Cell&quot; Monopoly</h2>\r\n<p>With Starship&rsquo;s massive cargo bay, SpaceX began deploying Starlink v3 satellites in late 2025. These satellites are nearly five times the size of their predecessors and feature massive phased-array antennas that provide universal 5G connectivity directly to standard smartphones.</p>\r\n<ul>\r\n  <li><strong>The Impact:</strong> &quot;Dead zones&quot; have effectively disappeared from the planet. In 2025, SpaceX announced partnerships with over 40 global carriers, making the &quot;satellite phone&quot; a feature of every iPhone and Android device, rather than a separate hardware requirement.</li>\r\n</ul>\r\n\r\n<h2>Commercial Real Estate in Orbit</h2>\r\n<p>The radical drop in launch costs triggered a construction boom in Low Earth Orbit (LEO). In 2025, Axiom Space and Vast began launching the first modules of their private space stations. Unlike the ISS, which is a research lab, these stations are being built for Industrialization and Tourism.</p>\r\n<ul>\r\n  <li><strong>Z-Gravity Manufacturing:</strong> High-purity fiber optics and certain pharmaceutical crystals are now being manufactured in orbit at scale, thanks to the cheap transport provided by Starship.</li>\r\n</ul>\r\n\r\n<h2>The Geopolitical Moon Race</h2>\r\n<p>Finally, 2025 saw the heat of the Artemis vs. ILRS (International Lunar Research Station) race. While NASA&rsquo;s Artemis II crewed flyby is slated for early 2026, the arrival of Blue Origin&rsquo;s New Glenn rocket in December 2025 (its maiden flight) signals that SpaceX finally has a domestic competitor. The &quot;New Space Race&quot; is no longer just between nations, but between billionaire-backed logistics companies.</p>\r\n<p>As we count down the final seconds of 2025, the final three pillars of our year-end report focus on the technologies that are rewriting the rules of physics, labor, and the very air we breathe.</p>\r\n`,\n        content: `The Year of the \"Starship Cadence\"\r\n\r\nRapid reusability and high cadence launches triggered a boom in orbital infrastructure and services.`\n    },\n    {\n        id: \"12\",\n        title: \"The Quantum Rubicon: IBM’s 4,000-Qubit Milestone and the NIST ‘Safe Harbor’\",\n        image: _assest_news12_png__WEBPACK_IMPORTED_MODULE_11__[\"default\"],\n        updated: \"Dec 31, 2025\",\n        author: \"The Unicorn Time\",\n        description: \"IBM scales modular quantum systems; NIST finalizes PQC standards—triggering the great encryption migration.\",\n        contentHtml: `\r\n<h2>The Birth of the Quantum Supercomputer</h2>\r\n<p>For years, quantum computing was a &quot;five-years-away&quot; technology. On December 12, 2025, that changed. IBM officially powered up its most ambitious machine to date: a modular Quantum System Two hosting three interconnected Kookaburra processors.</p>\r\n<p>By linking these chips through quantum communication links, IBM has achieved a total of 4,158 qubits in a single, unified system. This isn't just a bigger lab experiment; it is the world&rsquo;s first &quot;Quantum-Centric Supercomputer,&quot; where quantum processing units (QPUs) work alongside classical CPUs to solve problems in seconds that would take today's fastest supercomputers thousands of years.</p>\r\n\r\n<h2>The Physics of Error Mitigation</h2>\r\n<p>The breakthrough of 2025 wasn't just in qubit count, but in error mitigation.</p>\r\n<div class=\"equation\">E = 1 / (Connectivity × Coherence Time)</div>\r\n<p>As error rates dropped, IBM introduced Qiskit Runtime updates that allow developers to &quot;knit&quot; together circuits across multiple chips. We are now in the era of Practical Quantum Advantage, particularly in molecular simulation for battery chemistry and financial risk modeling.</p>\r\n\r\n<h2>Q-Day Awareness: The NIST Final Standards</h2>\r\n<p>While the hardware flourished, the cybersecurity world braced for &quot;Q-Day&quot;&mdash;the hypothetical day a quantum computer breaks RSA encryption. In late 2025, the NIST (National Institute of Standards and Technology) finalized its first three post-quantum cryptography (PQC) standards:</p>\r\n<ul>\r\n  <li><strong>FIPS 203 (ML-KEM):</strong> The primary standard for general encryption.</li>\r\n  <li><strong>FIPS 204 (ML-DSA):</strong> For protecting digital signatures.</li>\r\n  <li><strong>FIPS 205 (SLH-DSA):</strong> A stateless, hash-based backup for digital signatures.</li>\r\n</ul>\r\n<p>&quot;2025 was the year we stopped worrying about the threat and started installing the shield,&quot; says Dr. Sarah Chen, a lead cryptographer. Major blockchains like Aptos have already begun deploying these quantum-resistant layers, signaling a total overhaul of global digital security.</p>\r\n`,\n        content: `The Birth of the Quantum Supercomputer\r\n\r\nQuantum System Two crosses 4,000 qubits and the world adopts post-quantum cryptography standards.`\n    },\n    {\n        id: \"13\",\n        title: \"Gig Economy 3.0: The Rise of DePIN and the Decentralized Workforce\",\n        image: _assest_news13_png__WEBPACK_IMPORTED_MODULE_12__[\"default\"],\n        updated: \"Dec 31, 2025\",\n        author: \"The Unicorn Time\",\n        description: \"Platforms become protocols—DePIN networks and hybrid AI-web3 talent reshape distributed work.\",\n        contentHtml: `\r\n<h2>From Platforms to Protocols</h2>\r\n<p>In 2025, the &quot;Uber for X&quot; model began to feel like a relic of the past. The dominant story of the year was the explosion of DePIN (Decentralized Physical Infrastructure Networks). Instead of a central corporation owning the servers, cars, or 5G towers, the workers and users own the hardware and are rewarded in protocol tokens.</p>\r\n<p>Projects like Helium (5G), Hivemapper (Mapping), and Render (GPU Compute) reached a combined market cap of $42 Billion in 2025. This shift has created a new class of &quot;Fractional Technical Operators&quot; who earn a living by maintaining decentralized nodes or providing high-level AI-training data.</p>\r\n\r\n<h2>The AI-Web3 Talent Convergence</h2>\r\n<p>The &quot;Gig Economy 3.0&quot; isn't just about delivery; it’s about specialized intelligence. 2025 saw a massive hiring surge for &quot;Hybrid Professionals&quot;&mdash;people who can bridge the gap between AI and Blockchain.</p>\r\n<ul>\r\n  <li><strong>The New Resume:</strong> In 2025, a developer's value is measured by their ability to write &quot;Agentic Smart Contracts&quot; (contracts that execute automatically based on AI-derived data).</li>\r\n  <li><strong>Outcome-Based Compensation:</strong> Thanks to decentralized autonomous organizations (DAOs), project-based work now pays based on verifiable milestones recorded on-chain, rather than hours spent at a desk.</li>\r\n</ul>\r\n\r\n<h2>The &quot;Sovereign Worker&quot; Movement</h2>\r\n<p>As remote work stabilized into a permanent global fixture, &quot;Sovereign Workers&quot; began using AI agents (as seen in News 10) to manage multiple &quot;gigs&quot; simultaneously. In 2025, the average freelancer manages 3.4 different revenue streams through a single unified dashboard, effectively becoming a one-person corporation.</p>\r\n`,\n        content: `From Platforms to Protocols\r\n\r\nDePIN projects and outcome-based compensation redefine gig work and infrastructure ownership.`\n    },\n    {\n        id: \"14\",\n        title: \"Breathing Life Back: STRATOS and the Industrialization of Carbon Capture\",\n        image: _assest_news14_png__WEBPACK_IMPORTED_MODULE_13__[\"default\"],\n        updated: \"Dec 31, 2025\",\n        author: \"The Unicorn Time\",\n        description: \"Direct Air Capture becomes heavy industry as STRATOS scales and corporate carbon removal demand surges.\",\n        contentHtml: `\r\n<h2>The Gigaton Ambition</h2>\r\n<p>2025 will be remembered as the year Direct Air Capture (DAC) moved from &quot;science fiction&quot; to &quot;heavy industry.&quot; In late 2025, Occidental Petroleum&rsquo;s subsidiary, 1PointFive, officially switched on the fans at STRATOS in Texas. It is now the world&rsquo;s largest DAC facility, designed to pull 500,000 metric tons of CO<sub>2</sub> directly from the atmosphere annually.</p>\r\n\r\n<h2>The Microsoft Milestone</h2>\r\n<p>While STRATOS is the hardware star, the financial engine was a historic deal with Microsoft. In a transaction that redefined the &quot;Carbon Market,&quot; Microsoft committed to purchasing 500,000 metric tons of Carbon Dioxide Removal (CDR) credits. This is no longer about &quot;offsets&quot; (paying someone else not to cut down a tree); it is about active removal.</p>\r\n\r\n<h2>Modular Success: Iceland&rsquo;s &lsquo;Mammoth&rsquo;</h2>\r\n<p>Across the Atlantic, Climeworks reached full operational capacity at its Mammoth plant in Iceland.</p>\r\n<ul>\r\n  <li><strong>Scale:</strong> 36,000 tons of CO<sub>2</sub> per year.</li>\r\n  <li><strong>Method:</strong> The captured CO<sub>2</sub> is mixed with water and injected into basaltic rock formations by Carbfix, where it literally turns into stone within two years.</li>\r\n</ul>\r\n\r\n<h2>The Emerging &quot;Carbon-Negative&quot; Economy</h2>\r\n<p>By December 2025, the cost of capturing a ton of carbon has dropped from $1,000 in 2021 to approximately $450. While still high, the &quot;Learning Curve&quot; of 2025 suggests that the $100-per-ton holy grail is achievable by the early 2030s.</p>\r\n<p>&quot;We aren't just slowing down the damage anymore,&quot; noted a UN climate official at the year-end summit. &quot;In 2025, for the first time in human history, we started the process of cleaning up the last 150 years of industrial waste.&quot;</p>\r\n`,\n        content: `The Gigaton Ambition\r\n\r\n2025 moved DAC from concept to industrial deployment, with falling costs and rising commitments.`\n    },\n    {\n        id: \"15\",\n        title: \"The Mercor Phenomenon: How Three 22-Year-Olds Rewrote the Rules of Labor\",\n        image: _assest_news15_png__WEBPACK_IMPORTED_MODULE_14__[\"default\"],\n        updated: \"Dec 31, 2025\",\n        author: \"The Unicorn Time\",\n        description: \"Mercor scales a Human-in-the-Loop infrastructure for elite expertise and becomes a new index of capability.\",\n        contentHtml: `\r\n<h2>The $10 Billion &quot;Pivot&quot;</h2>\r\n<p>In the history of Silicon Valley, few companies have scaled with the velocity of Mercor. Founded in 2023 as a platform to connect Indian engineers with U.S. startups, Mercor underwent a radical transformation in 2025. By October 27, 2025, the company closed a $350 million Series C round led by Felicis Ventures, catapulting its valuation to $10 billion.</p>\r\n<p>The founders&mdash;all 22-year-old Thiel Fellows&mdash;have officially unseated Mark Zuckerberg as the youngest self-made billionaires in history.</p>\r\n\r\n<h2>The &quot;Expert-as-a-Service&quot; (EaaS) Model</h2>\r\n<p>Mercor&rsquo;s success stems from a counterintuitive bet: as AI gets smarter, it needs smarter humans. While competitors focused on low-wage data labeling, Mercor built a &quot;Human-in-the-Loop&quot; infrastructure for the elite.</p>\r\n<ul>\r\n  <li><strong>The Network:</strong> 30,000+ contractors including PhDs, lawyers, surgeons, and hedge fund analysts.</li>\r\n  <li><strong>The Payout:</strong> Mercor pays out over $1.5 million daily, with specialists earning between $90 and $200 per hour to &quot;teach&quot; AI models nuance, judgment, and &quot;taste.&quot;</li>\r\n  <li><strong>The Client List:</strong> Their proprietary &quot;Evals&quot; (evaluations) are now the gold standard for OpenAI, Anthropic, Google DeepMind, and Meta.</li>\r\n</ul>\r\n\r\n<h2>The &quot;Scale AI&quot; Power Vacuum</h2>\r\n<p>Mercor&rsquo;s ascent was accelerated by a massive shift in the competitive landscape. In June 2025, Meta acquired 49% of Scale AI for $14.3 billion. Fearing a conflict of interest, other major AI labs reportedly pulled their contracts from Scale, creating a vacuum that Mercor filled almost overnight.</p>\r\n\r\n<h2>Why It Matters for 2026</h2>\r\n<p>Mercor represents more than just a successful startup; it represents the &quot;Verticalization of Labor.&quot;</p>\r\n<div class=\"equation\">Labor Value = Domain Expertise + AI Alignment Ability</div>\r\n<p>By treating human intelligence as a high-octane fuel for AI models, Mercor has turned the &quot;threat&quot; of AI job loss on its head, creating a lucrative new category of work where professionals don't just do the work&mdash;they encode it for the next generation of agents</p>\r\n`,\n        content: `The $10 Billion \"Pivot\"\r\n\r\nMercor’s EaaS model and evals infrastructure became core to AI labs as the ecosystem shifted in 2025.`\n    },\n    {\n        id: \"16\",\n        title: \"Top 10 Predictions for 2026\",\n        image: _assest_news16_png__WEBPACK_IMPORTED_MODULE_15__[\"default\"],\n        updated: \"Dec 31, 2025\",\n        author: \"The Unicorn Time\",\n        description: \"A forward-looking playbook covering agents, space IPOs, quantum security, DePIN, and India’s IPO wave.\",\n        contentHtml: `\r\n<h2>Top 10 Predictions for 2026</h2>\r\n\r\n<h2>1. The &quot;Operator&quot; Era: AI Agents Get Their Own Paychecks</h2>\r\n<p>The novelty of chatting with AI will officially die. In 2026, we enter the era of Agentic AI. Organizations will stop buying &quot;software seats&quot; and start hiring &quot;Digital Employees.&quot; These agents won't just suggest code; they will manage procurement, handle end-to-end customer disputes, and even negotiate with other AI agents. By the end of 2026, 40% of enterprise workflows will be managed by &quot;Role-Based&quot; AI agents.</p>\r\n\r\n<h2>2. The $100 Billion Space IPO</h2>\r\n<p>With Starship&rsquo;s cadence reaching one launch per week, SpaceX is expected to finally pull the trigger on a massive Starlink or Starship IPO in the second half of 2026. This will be the &quot;Netscape Moment&quot; for the space economy, triggering a flood of capital into orbital manufacturing and lunar logistics. We predict a valuation floor of $250 Billion for the spun-off entity.</p>\r\n\r\n<h2>3. The &quot;Metabolic Supercycle&quot;</h2>\r\n<p>2026 will see the release of Gen-2 GLP-1 drugs that are cheaper, pill-based (no injections), and have fewer side effects. But the real breakthrough will be Suzetrigine and its successors&mdash;the first class of non-opioid pain relief that blocks peripheral pain without touching the brain&rsquo;s addiction centers. This will mark the beginning of the end for the opioid crisis in North America.</p>\r\n\r\n<h2>4. The Quantum Shield: &quot;Q-Day&quot; Preparation Goes Global</h2>\r\n<p>As IBM&rsquo;s 4,000-qubit systems begin simulating materials for the first &quot;Quantum-designed&quot; batteries, the cybersecurity world will panic. 2026 will be the year of the &quot;Great Encryption Migration.&quot; Banks and governments will rush to adopt the NIST-finalized Post-Quantum Cryptography (PQC) standards to prevent &quot;Harvest Now, Decrypt Later&quot; attacks by nation-states.</p>\r\n\r\n<h2>5. Energy Sovereignty: AI Firms Buy Their Own Power</h2>\r\n<p>The &quot;Compute-Energy Collision&quot; of 2025 will force a radical shift. In 2026, we will see the first major AI-Nuclear merger. Hyperscalers (Microsoft, Amazon, Google) will move beyond Power Purchase Agreements and start taking direct equity stakes in Small Modular Reactor (SMR) companies to ensure their data centers never go dark.</p>\r\n\r\n<h2>6. The Rise of &quot;DePIN&quot; (Decentralized Physical Infrastructure)</h2>\r\n<p>The centralized cloud is getting too expensive. In 2026, &quot;DePIN&quot; projects will become mainstream. Everyday people will earn passive income by hosting AI-inference nodes in their living rooms or 5G micro-cells on their balconies. This &quot;User-Owned Infrastructure&quot; will represent a $50 Billion market by year-end, challenging the monopolies of traditional telcos and cloud providers.</p>\r\n\r\n<h2>7. India&rsquo;s &quot;Reverse-Flip&quot; and IPO Wave</h2>\r\n<p>The Indian startup ecosystem will see its most successful year in history. We predict at least 15 major tech IPOs on the NSE/BSE in 2026. More importantly, &quot;Reverse-Flipping&quot; will become the norm, as startups originally incorporated in Delaware or Singapore move their headquarters back to India to take advantage of the massive domestic liquidity and favorable 2026 listing regulations.</p>\r\n\r\n<h2>8. The Perovskite Solar Pivot</h2>\r\n<p>The efficiency limit of traditional silicon solar panels (\\approx 24%) will be shattered commercially. In 2026, Tandem Perovskite-Silicon cells will hit the mass market, offering efficiencies of:</p>\r\n<div class=\"equation\">Efficiency ≥ 34%</div>\r\n<p>This 10% jump will make solar viable for &quot;space-constrained&quot; environments, turning every car roof and apartment window into a high-performance power plant.</p>\r\n\r\n<h2>9. The 2026 World Cup: A &quot;Mixed Reality&quot; Masterclass</h2>\r\n<p>The FIFA World Cup in North America will be the first &quot;AI-Native&quot; sporting event. Fans in the stadium will use AR glasses and 5G-Direct-to-Cell tech to see real-time player stats overlaying the field. For those at home, &quot;Volumetric Video&quot; will allow viewers to watch the match from the perspective of the ball or any player, essentially turning the live game into a playable video game.</p>\r\n\r\n<h2>10. The &quot;Sovereign Worker&quot; Movement</h2>\r\n<p>Traditional 9-to-5 employment will continue to erode for the top 10% of the workforce. Armed with personal AI &quot;Operator&quot; agents, the Sovereign Worker will emerge&mdash;individuals who manage 3&ndash;4 &quot;fractional&quot; roles at different companies simultaneously, using AI to handle the administrative and low-level cognitive load. The &quot;Chief Relationship Officer&quot; will become a more common title than &quot;Manager.&quot;</p>\r\n`,\n        content: `Top 10 Predictions for 2026\r\n\r\n1. The \"Operator\" Era: AI Agents Get Their Own Paychecks\r\n2. The $100 Billion Space IPO\r\n3. The \"Metabolic Supercycle\"\r\n4. The Quantum Shield: \"Q-Day\" Preparation Goes Global\r\n5. Energy Sovereignty: AI Firms Buy Their Own Power\r\n6. The Rise of \"DePIN\" (Decentralized Physical Infrastructure)\r\n7. India’s \"Reverse-Flip\" and IPO Wave\r\n8. The Perovskite Solar Pivot\r\n9. The 2026 World Cup: A \"Mixed Reality\" Masterclass\r\n10. The \"Sovereign Worker\" Movement\r\n\r\nFinal Note from the Editor: As we step into 2026, the gap between those who use AI and those who are \"AI-augmented\" will widen. The winners of the coming year won't just be the ones with the best technology, but the ones with the best human judgment to direct it.`\n    }\n];\nconst MARKET_NEWS_ASSET_IMAGES = [\n    _assest_news1_png__WEBPACK_IMPORTED_MODULE_0__[\"default\"],\n    _assest_news2_png__WEBPACK_IMPORTED_MODULE_1__[\"default\"],\n    _assest_news3_png__WEBPACK_IMPORTED_MODULE_2__[\"default\"],\n    _assest_news4_png__WEBPACK_IMPORTED_MODULE_3__[\"default\"],\n    _assest_news5_png__WEBPACK_IMPORTED_MODULE_4__[\"default\"],\n    _assest_news6_png__WEBPACK_IMPORTED_MODULE_5__[\"default\"],\n    _assest_news7_png__WEBPACK_IMPORTED_MODULE_6__[\"default\"],\n    _assest_news8_png__WEBPACK_IMPORTED_MODULE_7__[\"default\"],\n    _assest_news9_png__WEBPACK_IMPORTED_MODULE_8__[\"default\"],\n    _assest_news10_png__WEBPACK_IMPORTED_MODULE_9__[\"default\"],\n    _assest_news11_png__WEBPACK_IMPORTED_MODULE_10__[\"default\"],\n    _assest_news12_png__WEBPACK_IMPORTED_MODULE_11__[\"default\"],\n    _assest_news13_png__WEBPACK_IMPORTED_MODULE_12__[\"default\"],\n    _assest_news14_png__WEBPACK_IMPORTED_MODULE_13__[\"default\"],\n    _assest_news15_png__WEBPACK_IMPORTED_MODULE_14__[\"default\"],\n    _assest_news16_png__WEBPACK_IMPORTED_MODULE_15__[\"default\"]\n];\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///./src/data/marketNews.js\n");

